class ReceivedFile { final String transferId; final String fileName; final int fileSize; final String mimeType; final String downloadUrl; final String fromUid; final DateTime receivedAt; const ReceivedFile({required this.transferId, required this.fileName, required this.fileSize, required this.mimeType, required this.downloadUrl, required this.fromUid, required this.receivedAt}); factory ReceivedFile.fromJson(Map<String, dynamic> j) => ReceivedFile(transferId: j['transferId'] ?? '', fileName: j['fileName'] ?? '', fileSize: j['fileSize'] ?? 0, mimeType: j['mimeType'] ?? '', downloadUrl: j['url'] ?? '', fromUid: j['from'] ?? '', receivedAt: DateTime.now()); }